    prof_less: ["\u041A\u043E\u0443\u0447", "\u041F\u0441\u0438\u0445\u043E\u043B\u043E\u0433", "\u0421\u0442\u0438\u043B\u0438\u0441\u0442", "\u041C\u0435\u0434\u0438\u043A", "\u0421\u043E\u0446\u0440\u0430\u0431\u043E\u0442\u043D\u0438\u043A", "\u041A\u043E\u0441\u043C\u0435\u0442\u043E\u043B\u043E\u0433", "\u0414\u0438\u043F\u043B\u043E\u043C\u0430\u0442", "\u0424\u043E\u0442\u043E\u0433\u0440\u0430\u0444", "\u0420\u0435\u0441\u0442\u043E\u0440\u0430\u0442\u043E\u0440"],
