    strengths: ["\u041A\u0440\u0435\u0430\u0442\u0438\u0432\u043D\u043E\u0441\u0442\u044C \u0438 \u043E\u0440\u0438\u0433\u0438\u043D\u0430\u043B\u044C\u043D\u043E\u0441\u0442\u044C", "\u0413\u0438\u0431\u043A\u043E\u0441\u0442\u044C \u0443\u043C\u0430", "\u0427\u0435\u0441\u0442\u043D\u043E\u0441\u0442\u044C \u0438 \u043E\u0442\u043A\u0440\u044B\u0442\u043E\u0441\u0442\u044C", "\u0412\u044B\u0441\u043E\u043A\u0438\u0439 \u0438\u043D\u0442\u0435\u043B\u043B\u0435\u043A\u0442", "\u0416\u0435\u043B\u0430\u043D\u0438\u0435 \u0440\u0430\u0437\u0432\u0438\u0432\u0430\u0442\u044C\u0441\u044F", "\u0423\u043C\u0435\u043D\u0438\u0435 \u043F\u0440\u0435\u0434\u0432\u0438\u0434\u0435\u0442\u044C \u0431\u0443\u0434\u0443\u0449\u0435\u0435", "\u041C\u043E\u0449\u043D\u0430\u044F \u0438\u043D\u0442\u0443\u0438\u0446\u0438\u044F", "\u0420\u0430\u0431\u043E\u0442\u0430 \u0432 \u0434\u0435\u0434\u043B\u0430\u0439\u043D\u0435 \u0438 \u043A\u0440\u0438\u0437\u0438\u0441\u0435"],
    weaknesses: ["\u041D\u0435\u043E\u0440\u0433\u0430\u043D\u0438\u0437\u043E\u0432\u0430\u043D\u043D\u043E\u0441\u0442\u044C", "\u041E\u043F\u043E\u0437\u0434\u0430\u043D\u0438\u044F, \u0441\u0440\u044B\u0432 \u0434\u0435\u0434\u043B\u0430\u0439\u043D\u043E\u0432", "\u041D\u0435\u0443\u0441\u0442\u0443\u043F\u0447\u0438\u0432\u043E\u0441\u0442\u044C", "\u041D\u0435\u0442 \u0441\u0430\u043C\u043E\u0434\u0438\u0441\u0446\u0438\u043F\u043B\u0438\u043D\u044B", "\u041E\u0442\u0440\u0438\u0446\u0430\u043D\u0438\u0435 \u0440\u0443\u0442\u0438\u043D\u044B", "\u0421\u043B\u043E\u0436\u043D\u043E \u0434\u043E\u0432\u043E\u0434\u0438\u0442\u044C \u0434\u043E \u043A\u043E\u043D\u0446\u0430", "\u0411\u0443\u043D\u0442 \u043F\u0440\u043E\u0442\u0438\u0432 \u043F\u0440\u0430\u0432\u0438\u043B"],
    grow: ["\u0427\u0430\u0449\u0435 \xAB\u0437\u0430\u0437\u0435\u043C\u043B\u044F\u0442\u044C\u0441\u044F\xBB (\u0441\u043F\u043E\u0440\u0442, \u0442\u0435\u043B\u0435\u0441\u043D\u044B\u0435 \u043F\u0440\u0430\u043A\u0442\u0438\u043A\u0438), \u0447\u0442\u043E\u0431\u044B \u043D\u0435 \xAB\u0443\u043B\u0435\u0442\u0435\u0442\u044C\xBB", "\u0414\u043E\u0432\u043E\u0434\u0438\u0442\u044C \u0438\u0434\u0435\u0438 \u0434\u043E \u043A\u043E\u043D\u0446\u0430 \u0438 \u0437\u0430\u0449\u0438\u0449\u0430\u0442\u044C \u0430\u0432\u0442\u043E\u0440\u0441\u0442\u0432\u043E, \u0434\u0435\u043B\u0435\u0433\u0438\u0440\u043E\u0432\u0430\u0442\u044C \u0440\u0435\u0430\u043B\u0438\u0437\u0430\u0446\u0438\u044E"],
    prof_fit: ["\u0421\u0442\u0430\u0440\u0442\u0430\u043F\u0435\u0440", "IT-\u0441\u043F\u0435\u0446\u0438\u0430\u043B\u0438\u0441\u0442, \u0440\u0430\u0437\u0440\u0430\u0431\u043E\u0442\u0447\u0438\u043A", "R&D", "\u041A\u0440\u0435\u0430\u0442\u0438\u0432\u043D\u044B\u0439 \u043C\u0430\u0440\u043A\u0435\u0442\u043E\u043B\u043E\u0433", "\u0413\u0440\u0430\u0444\u0438\u0447\u0435\u0441\u043A\u0438\u0439 \u0434\u0438\u0437\u0430\u0439\u043D\u0435\u0440", "\u0418\u043D\u043D\u043E\u0432\u0430\u0446\u0438\u043E\u043D\u043D\u044B\u0435 \u0444\u0438\u043D\u0430\u043D\u0441\u044B", "\u041D\u0430\u0443\u0447\u043D\u043E-\u0438\u0441\u0441\u043B\u0435\u0434\u043E\u0432\u0430\u0442\u0435\u043B\u044C\u0441\u043A\u0430\u044F \u0434\u0435\u044F\u0442\u0435\u043B\u044C\u043D\u043E\u0441\u0442\u044C", "\u041A\u043E\u043F\u0438\u0440\u0430\u0439\u0442\u0435\u0440", "SMM-\u0441\u0442\u0440\u0430\u0442\u0435\u0433", "\u041F\u0440\u043E\u0434\u0430\u043A\u0442-\u043C\u0435\u043D\u0435\u0434\u0436\u0435\u0440 \u0438\u043D\u043D\u043E\u0432\u0430\u0446\u0438\u0439"],
    prof_less: ["\u041C\u0435\u043D\u0435\u0434\u0436\u0435\u0440 \u043F\u043E \u043F\u0440\u043E\u0434\u0430\u0436\u0430\u043C", "\u041E\u043F\u0435\u0440\u0430\u0446\u0438\u043E\u043D\u043D\u044B\u0439 \u0434\u0438\u0440\u0435\u043A\u0442\u043E\u0440", "\u0410\u043A\u043A\u0430\u0443\u043D\u0442-\u043C\u0435\u043D\u0435\u0434\u0436\u0435\u0440", "\u041F\u0441\u0438\u0445\u043E\u043B\u043E\u0433", "\u0421\u0435\u043A\u0440\u0435\u0442\u0430\u0440\u044C, \u0430\u0441\u0441\u0438\u0441\u0442\u0435\u043D\u0442", "HR", "\u041E\u0440\u0433\u0430\u043D\u0438\u0437\u0430\u0442\u043E\u0440 \u043C\u0435\u0440\u043E\u043F\u0440\u0438\u044F\u0442\u0438\u0439", "\u041A\u043E\u0443\u0447"],
    famous: ["\u0421\u0435\u0440\u0433\u0435\u0439 \u0411\u0440\u0438\u043D", "\u0410\u043B\u044C\u0431\u0435\u0440\u0442 \u042D\u0439\u043D\u0448\u0442\u0435\u0439\u043D", "\u0421\u0442\u0438\u0432 \u0414\u0436\u043E\u0431\u0441", "\u0414\u0436\u043E\u043D \u041B\u0435\u043D\u043D\u043E\u043D", "\u0414\u0436\u0435\u0444\u0444 \u0411\u0435\u0437\u043E\u0441", "\u0411\u0430\u0440\u0430\u043A \u041E\u0431\u0430\u043C\u0430"]
