    prof_less: ["\u041A\u043E\u0443\u0447", "\u041C\u0435\u043D\u0435\u0434\u0436\u0435\u0440 \u043F\u043E \u043F\u0440\u043E\u0434\u0430\u0436\u0430\u043C", "PR-\u043C\u0435\u043D\u0435\u0434\u0436\u0435\u0440", "HR-\u043C\u0435\u043D\u0435\u0434\u0436\u0435\u0440", "\u0420\u0435\u043A\u0440\u0443\u0442\u0435\u0440", "SMM-\u043C\u0435\u043D\u0435\u0434\u0436\u0435\u0440", "\u041F\u0441\u0438\u0445\u043E\u043B\u043E\u0433", "\u0410\u043A\u0442\u0451\u0440", "\u041E\u0440\u0433\u0430\u043D\u0438\u0437\u0430\u0442\u043E\u0440 \u043C\u0435\u0440\u043E\u043F\u0440\u0438\u044F\u0442\u0438\u0439"],
