    grow: ["\u041F\u043B\u0430\u043D\u0438\u0440\u043E\u0432\u0430\u0442\u044C \xAB\u043F\u043E\u043C\u043E\u0449\u044C \u0434\u0440\u0443\u0433\u0438\u043C\xBB, \u0447\u0442\u043E\u0431\u044B \u043D\u0435 \u0441\u0442\u0440\u0430\u0434\u0430\u043B\u0438 \u0441\u0432\u043E\u0438 \u043F\u0440\u0438\u043E\u0440\u0438\u0442\u0435\u0442\u044B", "\u041F\u0440\u0438\u043D\u044F\u0442\u044C \u0438\u043C\u043F\u0443\u043B\u044C\u0441\u0438\u0432\u043D\u043E\u0441\u0442\u044C; \u0441\u043E\u0432\u0435\u0442\u043E\u0432\u0430\u0442\u044C\u0441\u044F \u0441 \u0445\u043B\u0430\u0434\u043D\u043E\u043A\u0440\u043E\u0432\u043D\u044B\u043C\u0438 (\u0412+\u0421-, \u0421-\u0412+)"],
    prof_fit: ["\u0414\u0438\u0437\u0430\u0439\u043D\u0435\u0440", "\u0420\u0435\u0441\u0442\u043E\u0440\u0430\u043D\u043D\u044B\u0439 \u0431\u0438\u0437\u043D\u0435\u0441 (\u0448\u0435\u0444-\u043F\u043E\u0432\u0430\u0440, \u0441\u043E\u043C\u0435\u043B\u044C\u0435)", "\u041F\u0430\u0440\u0444\u044E\u043C\u0435\u0440\u0438\u044F", "\u0418\u043D\u0434\u0443\u0441\u0442\u0440\u0438\u044F \u043A\u0440\u0430\u0441\u043E\u0442\u044B", "\u041C\u0435\u043D\u0435\u0434\u0436\u0435\u0440 \u043F\u043E \u043F\u0440\u043E\u0434\u0430\u0436\u0430\u043C", "\u0414\u0438\u0440\u0435\u043A\u0442\u043E\u0440 \u043F\u043E HR", "PR-\u043C\u0435\u043D\u0435\u0434\u0436\u0435\u0440", "\u0428\u043E\u0443\u0431\u0438\u0437\u043D\u0435\u0441", "\u041E\u0440\u0433\u0430\u043D\u0438\u0437\u0430\u0442\u043E\u0440 \u043C\u0435\u0440\u043E\u043F\u0440\u0438\u044F\u0442\u0438\u0439", "\u041A\u043E\u043D\u0434\u0438\u0442\u0435\u0440, \u0444\u0443\u0434-\u0438\u043D\u0434\u0443\u0441\u0442\u0440\u0438\u044F"],
