function scoreDirections(answers) {
  const s = { \u0421: 0, \u042E: 0, \u0417: 0, \u0412: 0 };
  for (const q of QUESTIONS) {
    const a = answers[q.id];
    if (q.type === "choice") {
      const opt = q.options.find((o) => o.label === a);
      if (opt && opt.w) for (const k in opt.w) s[k] += opt.w[k];
    } else if (q.type === "scale" && typeof a === "number" && q.dir) {
      s[q.dir] += a - 1;
    }
  }
  return s;
}
function familyOf(s) {
  const vert = s.\u0421 >= s.\u042E ? "\u0421" : "\u042E";
  const horiz = s.\u0417 >= s.\u0412 ? "\u0417" : "\u0412";
  return vert + horiz;
}
function polarityBonus(code, answers) {
  let b = 0;
  const az = answers.q14, em = answers.q15, nov = answers.q16;
  if (typeof az === "number") {
    if (az >= 4 && code.includes("\u0417+")) b += 1.5;
    if (az <= 2 && code.includes("\u0417-")) b += 1.5;
  }
  if (typeof em === "number") {
    if (em >= 4 && code.includes("\u042E+")) b += 1.5;
    if (em <= 2 && code.includes("\u042E-")) b += 1.5;
  }
  if (typeof nov === "number") {
    if (nov >= 4 && code.includes("\u0412+")) b += 1.5;
    if (nov <= 2 && code.includes("\u0412-")) b += 1.5;
  }
  return b;
}
function scoreFamily(family, answers, discAnswers) {
  const rows = FAMILIES[family].map((code) => {
    const st = (discAnswers[code + "_0"] || 0) + (discAnswers[code + "_1"] || 0);
    const bonus = polarityBonus(code, answers);
    return { code, statements: st, bonus, total: st + bonus };
  });
  rows.sort((a, b) => b.total - a.total);
  return rows;
}
