    cons: ["\u041D\u0430 \u043F\u0440\u0435\u0441\u0442\u0438\u0436\u043D\u044B\u0445 \u043D\u0430\u043F\u0440\u0430\u0432\u043B\u0435\u043D\u0438\u044F\u0445 \u0442\u043E\u043F-\u0432\u0443\u0437\u043E\u0432 \u0437\u0430\u043C\u0435\u0442\u043D\u0430\u044F \u0447\u0430\u0441\u0442\u044C \u0431\u044E\u0434\u0436\u0435\u0442\u043D\u044B\u0445 \u043C\u0435\u0441\u0442 \u0440\u0430\u0441\u043F\u0440\u0435\u0434\u0435\u043B\u044F\u0435\u0442\u0441\u044F \u043F\u043E \u043A\u0432\u043E\u0442\u0430\u043C (\u0446\u0435\u043B\u0435\u0432\u0430\u044F, \u043E\u0441\u043E\u0431\u0430\u044F, \u043E\u0442\u0434\u0435\u043B\u044C\u043D\u0430\u044F) \u0438 \u043E\u043B\u0438\u043C\u043F\u0438\u0430\u0434\u043D\u0438\u043A\u0430\u043C \u0411\u0412\u0418 \u2014 \u043A\u043E\u043D\u043A\u0443\u0440\u0441 \u043F\u043E \u0431\u0430\u043B\u043B\u0430\u043C \u0415\u0413\u042D \u0438\u0434\u0451\u0442 \u0437\u0430 \u043E\u0441\u0442\u0430\u0432\u0448\u0438\u0435\u0441\u044F \u043C\u0435\u0441\u0442\u0430", "\u0421 2025 \u0433\u043E\u0434\u0430 \u0433\u043E\u0441\u0443\u0434\u0430\u0440\u0441\u0442\u0432\u043E \u043E\u0433\u0440\u0430\u043D\u0438\u0447\u0438\u0432\u0430\u0435\u0442 \u0434\u0430\u0436\u0435 \u043F\u043B\u0430\u0442\u043D\u044B\u0439 \u043F\u0440\u0438\u0451\u043C: \u043D\u0430 2026/27 \u0432\u0432\u0435\u0434\u0435\u043D\u044B \u043A\u0432\u043E\u0442\u044B \u043F\u043E ~40 \u043F\u043E\u043F\u0443\u043B\u044F\u0440\u043D\u044B\u043C \u043D\u0430\u043F\u0440\u0430\u0432\u043B\u0435\u043D\u0438\u044F\u043C (\u044E\u0440\u0438\u0441\u043F\u0440\u0443\u0434\u0435\u043D\u0446\u0438\u044F, \u043C\u0435\u043D\u0435\u0434\u0436\u043C\u0435\u043D\u0442 \u0438 \u0434\u0440.), \u0441\u043E\u043A\u0440\u0430\u0449\u0435\u043D\u043E \u224845 \u0442\u044B\u0441. \u043F\u043B\u0430\u0442\u043D\u044B\u0445 \u043C\u0435\u0441\u0442", "\u0420\u044F\u0434\u0430 \u0441\u043E\u0432\u0440\u0435\u043C\u0435\u043D\u043D\u044B\u0445 \u0441\u043F\u0435\u0446\u0438\u0430\u043B\u044C\u043D\u043E\u0441\u0442\u0435\u0439 \u0432 \u0420\u043E\u0441\u0441\u0438\u0438 \u043D\u0435\u0442 \u0438\u043B\u0438 \u043F\u0440\u043E\u0433\u0440\u0430\u043C\u043C\u044B \u0435\u0434\u0438\u043D\u0438\u0447\u043D\u044B; \u043F\u043E \u0442\u0435\u0445\u043D\u043E\u043B\u043E\u0433\u0438\u0447\u0435\u0441\u043A\u0438\u043C \u043D\u0430\u043F\u0440\u0430\u0432\u043B\u0435\u043D\u0438\u044F\u043C \u0432\u0443\u0437\u044B \u0441\u043B\u0430\u0431\u043E \u043F\u0440\u0435\u0434\u0441\u0442\u0430\u0432\u043B\u0435\u043D\u044B \u0432 \u043C\u0438\u0440\u043E\u0432\u044B\u0445 \u043F\u0440\u0435\u0434\u043C\u0435\u0442\u043D\u044B\u0445 \u0440\u0435\u0439\u0442\u0438\u043D\u0433\u0430\u0445, \u043E\u0433\u0440\u0430\u043D\u0438\u0447\u0435\u043D \u0434\u043E\u0441\u0442\u0443\u043F \u043A \u043C\u0435\u0436\u0434\u0443\u043D\u0430\u0440\u043E\u0434\u043D\u044B\u043C \u043E\u0431\u043C\u0435\u043D\u0430\u043C \u0438 \u043E\u0431\u043E\u0440\u0443\u0434\u043E\u0432\u0430\u043D\u0438\u044E"],
    future: "\u0420\u0430\u0431\u043E\u0447\u0430\u044F \u0441\u0442\u0440\u0430\u0442\u0435\u0433\u0438\u044F \u2014 \xAB\u0431\u0430\u0437\u0430 \u0434\u043E\u043C\u0430 \u2192 \u043C\u0430\u0433\u0438\u0441\u0442\u0440\u0430\u0442\u0443\u0440\u0430 \u0437\u0430 \u0440\u0443\u0431\u0435\u0436\u043E\u043C\xBB, \u043D\u043E \u0441 2026 \u0433\u043E\u0434\u0430 \u0435\u0451 \u043D\u0430\u0434\u0451\u0436\u043D\u043E\u0441\u0442\u044C \u043F\u0430\u0434\u0430\u0435\u0442: \u043A\u0430\u043A \u0438\u043D\u043E\u0441\u0442\u0440\u0430\u043D\u043D\u044B\u0435 \u0432\u0443\u0437\u044B \u0431\u0443\u0434\u0443\u0442 \u043F\u0440\u0438\u0437\u043D\u0430\u0432\u0430\u0442\u044C \u0434\u0438\u043F\u043B\u043E\u043C\u044B \u043D\u043E\u0432\u043E\u0439 \u0440\u043E\u0441\u0441\u0438\u0439\u0441\u043A\u043E\u0439 \u0441\u0438\u0441\u0442\u0435\u043C\u044B, \u043F\u043E\u043A\u0430 \u043D\u0435 \u043E\u043F\u0440\u0435\u0434\u0435\u043B\u0435\u043D\u043E.",
